import{_ as n,c as i,o as r,ag as t}from"./chunks/framework.091VdYs-.js";const m=JSON.parse('{"title":"Bewerber-Schmiede","description":"","frontmatter":{"aside":true},"headers":[],"relativePath":"projekte/bewerber-schmiede.md","filePath":"projekte/bewerber-schmiede.md"}'),s={name:"projekte/bewerber-schmiede.md"};function a(d,e,h,u,l,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="bewerber-schmiede" tabindex="-1">Bewerber-Schmiede <a class="header-anchor" href="#bewerber-schmiede" aria-label="Permalink to &quot;Bewerber-Schmiede&quot;">​</a></h1><p><strong>Web-Anwendung · In Betrieb · <a href="https://bewerber-schmiede.de" target="_blank" rel="noreferrer">bewerber-schmiede.de</a></strong></p><p>Bewerber-Schmiede ist ein Tool, mit dem man Lebensläufe analysieren kann. Wer seinen Lebenslauf einreicht, bekommt strukturiertes Feedback zu Vollständigkeit, Formulierungen, häufigen Schwachstellen und konkreten Verbesserungsvorschlägen. Das Ziel: nicht eine allgemeine Kritik, sondern spezifische, handlungsrelevante Hinweise.</p><h2 id="der-hintergrund" tabindex="-1">Der Hintergrund <a class="header-anchor" href="#der-hintergrund" aria-label="Permalink to &quot;Der Hintergrund&quot;">​</a></h2><p>Die Idee entstand aus Gesprächen. Wer Freunde oder Bekannte bei der Jobsuche unterstützt, gibt immer wieder ähnliche Hinweise: Fehlende Quantifizierungen bei Leistungen, zu generische Formulierungen, unklare Zeiträume, fehlende Keywords für Recruiter-Screening-Systeme. Das ist kein Spezialistenwissen, aber es ist Wissen, das nicht überall gleich zugänglich ist. Ein Tool, das das systematisch und sofort liefert, hat einen praktischen Wert.</p><h2 id="warum-dieses-projekt-besonders-ist" tabindex="-1">Warum dieses Projekt besonders ist <a class="header-anchor" href="#warum-dieses-projekt-besonders-ist" aria-label="Permalink to &quot;Warum dieses Projekt besonders ist&quot;">​</a></h2><p>Bewerber-Schmiede ist in erster Linie ein technisches Experiment – aber eines mit ernstem Charakter. Ich habe dieses Projekt vollständig mit Claude Code als Entwicklungspartner gebaut. Das bedeutet nicht, dass eine KI den Code geschrieben und ich nur zugeschaut habe. Es bedeutet, dass ich mit einem KI-Werkzeug gearbeitet habe, das in der Lage ist, Code zu verstehen, Entscheidungen zu besprechen, Refactoring-Vorschläge zu machen und Fehler zu finden – und dass ich diesen Workflow konsequent auf das gesamte Projekt angewendet habe, von der ersten Zeile bis zum Deployment.</p><p>Das hat meine Arbeitsweise verändert. Nicht in dem Sinne, dass ich jetzt weniger denke – im Gegenteil. Die Auseinandersetzung mit einem Werkzeug, das Gegenvorschläge macht und Begründungen einfordert, hat mich dazu gebracht, Entscheidungen expliziter zu machen als ich es alleine getan hätte. Warum diese Architektur? Warum dieser Trade-off? Warum jetzt Feature A und nicht Feature B? Diese Fragen muss man beantworten können, wenn man mit einem Werkzeug arbeitet, das sie stellt.</p><h2 id="entwicklung-und-infrastruktur" tabindex="-1">Entwicklung und Infrastruktur <a class="header-anchor" href="#entwicklung-und-infrastruktur" aria-label="Permalink to &quot;Entwicklung und Infrastruktur&quot;">​</a></h2><p>Das Besondere an Bewerber-Schmiede aus technischer Sicht ist nicht die Anwendung selbst, sondern wie sie gebaut und betrieben wird. Von Anfang an mit dem Anspruch, dass dieses Projekt die Qualitätsstandards erfüllt, die ich auch an berufliche Projekte anlege.</p><p><strong>CI/CD-Pipeline.</strong> Jede Änderung, die auf den Hauptzweig gepusht wird, durchläuft automatisch eine Build-Pipeline. Kein manuelles Deployment, keine &quot;ich deploye das nachher mal&quot;-Mentalität. Die Pipeline prüft, baut und deployt – oder schlägt mit einer klaren Fehlermeldung fehl.</p><p><strong>Automatisierte Unit-Tests.</strong> Die Geschäftslogik ist durch Unit-Tests abgedeckt. Nicht flächendeckend nach Prozentsatz optimiert, sondern durchdacht: die Teile, die wahrscheinlich brechen, sind getestet. Die Teile, bei denen ein Test mehr Aufwand als Nutzen wäre, sind dokumentiert.</p><p><strong>End-to-End-Tests.</strong> Über die Unit-Tests hinaus gibt es End-to-End-Tests, die die gesamte Anwendung aus Nutzerperspektive testen. Formular ausfüllen, Analyse auslösen, Ergebnis prüfen. Das fängt Fehler, die in isolierten Tests unsichtbar bleiben.</p><p><strong>Automatisiertes Deployment.</strong> Nach erfolgreich durchlaufenen Tests wird automatisch deployed. Kein manueller Eingriff, keine SSH-Session auf dem Server.</p><h2 id="was-ich-daraus-gelernt-habe" tabindex="-1">Was ich daraus gelernt habe <a class="header-anchor" href="#was-ich-daraus-gelernt-habe" aria-label="Permalink to &quot;Was ich daraus gelernt habe&quot;">​</a></h2><p>Zwei Dinge haben mich bei diesem Projekt überrascht.</p><p>Das erste: Wie viel Disziplin es braucht, auch bei einem Nebenprojekt ohne externe Deadline konsequent auf Qualität zu bestehen. Es ist verlockend, für ein kleines Nebenprojekt den CI/CD-Aufwand als Überengineering zu betrachten und einfach manuell zu deployen. Ich habe das bewusst nicht getan – und bin froh darüber. Die Pipeline hat mir mehrfach Fehler gezeigt, die ich ohne sie in Produktion gepusht hätte.</p><p>Das zweite: Die KI-gestützte Entwicklung mit Claude Code ist kein Gimmick. Es ist ein echter Wandel in der Arbeitsweise, vergleichbar damit, wie das Aufkommen guter Linters und Formatter die Codequalität in der Breite verändert hat. Wer lernt wie man mit diesem Werkzeug arbeitet – nicht als Abkürzung, sondern als Gesprächspartner – verändert seine Entwicklungsgeschwindigkeit und seine Codequalität gleichzeitig.</p><hr><p><a href="https://bewerber-schmiede.de" class="cv-download-link" target="_blank" rel="noreferrer">Zur Bewerber-Schmiede</a></p>',20)])])}const b=n(s,[["render",a]]);export{m as __pageData,b as default};
